fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }
    let mut sieve = vec![true; n];
    sieve[0] = false;
    sieve[1] = false;
    let max_i = (n as f64).sqrt() as i32;
    for i in 2..=max_i {
        if sieve[i] {
            let mut j = i * i;
            while j < n {
                sieve[j] = false;
                j += i;
            }
        }
    }
    let mut sum_a = 0;
    let mut sum_b = 0;
    for i in 0..n {
        if sieve[i] {
            sum_a += nums[i];
        } else {
            sum_b += nums[i];
        }
    }
    (sum_a - sum_b).abs()
}
```

