#include <vector>
#include <cstdlib>

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;
    std::vector<bool> sieve(n, true);
    sieve[0] = sieve[1] = false;
    for (int i = 2; i * i <= n - 1; i++) {
        if (sieve[i]) {
            for (int j = i * i; j < n; j += i) {
                sieve[j] = false;
            }
        }
    }
    long long sumA = 0;
    long long sumB = 0;
    for (int i = 0; i < n; i++) {
        if (sieve[i]) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }
    return std::abs(sumA - sumB);
}
